  source_url, statute_citation, version
) values ('20000000-0000-4000-8000-000000000001', 'state', '*', null, 'universal-state-annual-entity-filing', '${state} Annual Report / Entity Filing', 'Annual state entity report for ${entityTypeUpper} in ${state}. Failure to file can result in administrative dissolution.', 'entity_filing', '${state} Secretary of State', 'annual', '{"kind":"years_from_today","years":1}'::jsonb, '{"state_any":true,"entity_in":["llc","s_corp","c_corp"]}'::jsonb, 'high', 10000, null, null, 1)
